-- Migracion manual (pgAdmin) -- importa el historial de observaciones dentro
-- de cada revision (RevisionesArqCom.csv, ~1000 filas, app legacy Power Apps).
-- Ejecutar directamente contra PostgreSQL. NO usar dotnet ef.
--
-- Requiere que ya exista el catalogo de 22 revisiones importado por
-- 20260715_ImportRevisionesHistorico.sql (ac_revisiones).
--
-- El IDProyecto del CSV es el ID interno de la lista de SharePoint, NO el
-- project_id real de Abril. Se mapea a mano (VALUES abajo) al NOMBRE de
-- proyecto y se une contra la tabla project real por nombre -- nunca se
-- usa el IDProyecto como project_id.
--
-- La columna "Revision" del CSV a veces trae solo el codigo de tipo
-- (R1, R2, R1-AC...) y a veces el nombre completo generado
-- (ej. "R1-Kaurí-Pilotos"). Se parseo en dos columnas: tipo (codigo corto)
-- y lugar_resuelto (Pilotos / Sala de ventas / Areas comunes / Comedor /
-- Sala de juegos de niños), detectado por palabra clave dentro del nombre
-- completo, del campo libre "Lugar" de la observacion, o de la
-- Descripcion (para ambientes tipicos de un piloto como "dormitorio",
-- "lavanderia", "coworking", "SUM"). Cuando el proyecto+tipo tiene una
-- sola revision en el catalogo, no hace falta lugar_resuelto para
-- desambiguar.
--
-- Unico caso realmente ambiguo: Kaurí R1 (tiene dos revisiones R1:
-- Pilotos y Sala de ventas). Sus filas vienen con Revision="R1" (sin
-- nombre completo) y sin palabra clave individual, PERO todas pertenecen
-- a dos lotes de visita (mismo proyecto+tipo+fecha, codigos KAU-41 a
-- KAU-49 del 20/02/2026 y KAU-69 a KAU-75 del 13/04/2026) donde otras
-- filas del mismo lote SI confirman "Pilotos" por texto (ej. KAU-48:
-- "antes de ingresar a piloto"). Se resolvieron heredando el lugar de su
-- propio lote -- verificado a mano, no debería quedar ninguna fila de
-- Kaurí R1 en el SELECT final de "no mapeadas".
--
-- Re-ejecutable sin duplicar: primero BORRA cualquier importacion previa
-- marcada con origen='Import' (incluye la corrida parcial de 334 filas
-- que quedo del intento anterior) y vuelve a insertar todo desde cero.
-- Esto no toca observaciones creadas manualmente desde la app (esas usan
-- origen distinto de 'Import').
--
-- IMPORTANTE: correr el script COMPLETO de una sola vez (Ctrl+A -> F5
-- sobre todo el archivo) -- las tablas temporales solo viven dentro de la
-- misma sesion/conexion de pgAdmin; si ejecutas las consultas una por una
-- en pestañas o sesiones distintas, las que usan staging_revision_obs
-- fallaran con "relation does not exist".

DELETE FROM ac_revision_observaciones WHERE origen = 'Import';

DROP TABLE IF EXISTS staging_revision_obs;

CREATE TEMP TABLE staging_revision_obs (
  proyecto_nombre text,
  tipo text,
  lugar_resuelto text,
  lugar_obs text,
  fecha text,
  persona_reporta text,
  partida text,
  estado text,
  descripcion text,
  creado text,
  plazo text,
  fecha_levantamiento text,
  codigo text
);


SELECT
  m.revision_id,
  m.fecha::timestamp,
  m.persona_reporta,
  m.lugar_obs,
  m.partida,
  m.descripcion,
  m.estado,
  CASE WHEN m.plazo IS NOT NULL THEN m.plazo::timestamp ELSE NULL END,
  'Importacion historica SharePoint',
  'Import',
  (now() AT TIME ZONE 'utc'),
  CASE WHEN m.fecha_levantamiento IS NOT NULL THEN m.fecha_levantamiento::timestamp ELSE NULL END
FROM (
  SELECT
    s.*,
    rev.id AS revision_id
  FROM staging_revision_obs s
  JOIN project p ON upper(p.project_description) = s.proyecto_nombre
  LEFT JOIN ac_revisiones rev ON rev.proyecto_id = p.project_id
    AND rev.tipo = s.tipo
    AND (
      (s.lugar_resuelto IS NOT NULL AND rev.lugar = s.lugar_resuelto)
      OR (
        s.lugar_resuelto IS NULL
        AND (SELECT count(*) FROM ac_revisiones r2 WHERE r2.proyecto_id = p.project_id AND r2.tipo = s.tipo) = 1
      )
    )
) m
WHERE m.revision_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM ac_revision_observaciones existente
    WHERE existente.revision_id = m.revision_id
      AND existente.fecha = m.fecha::timestamp
      AND existente.descripcion = m.descripcion
  );

-- Verificacion: avisa el total importado en el panel de "Messages" de
-- pgAdmin (no en "Data Output"), para que se vea siempre sin importar
-- cual fue la ultima sentencia del script.
DO $$
DECLARE
  v_total integer;
  v_sin_mapear integer;
BEGIN
  SELECT count(*) INTO v_total FROM ac_revision_observaciones WHERE origen = 'Import';

  SELECT count(*) INTO v_sin_mapear
  FROM staging_revision_obs s
  LEFT JOIN project p ON upper(p.project_description) = s.proyecto_nombre
  LEFT JOIN ac_revisiones rev ON rev.proyecto_id = p.project_id
    AND rev.tipo = s.tipo
    AND (
      (s.lugar_resuelto IS NOT NULL AND rev.lugar = s.lugar_resuelto)
      OR (
        s.lugar_resuelto IS NULL
        AND (SELECT count(*) FROM ac_revisiones r2 WHERE r2.proyecto_id = p.project_id AND r2.tipo = s.tipo) = 1
      )
    )
  WHERE rev.id IS NULL;

  RAISE NOTICE 'Observaciones importadas (origen=Import): %', v_total;
  RAISE NOTICE 'Filas del CSV sin mapear a ninguna revision: %', v_sin_mapear;
END $$;

-- Filas del CSV que NO se pudieron mapear a ninguna revision existente
-- (proyecto no encontrado en project, proyecto+tipo sin revision
-- catalogada, o ambiguedad no resuelta). Esta es la ULTIMA sentencia del
-- script a proposito: pgAdmin (Execute Script / F5) solo muestra en
-- "Data Output" el resultado de la ultima consulta -- si esta tabla sale
-- vacia, quiere decir que se mapeo el 100% de las filas.
-- Revisar a mano: puede requerir crear una revision adicional en el
-- catalogo (modulo Gestion de Revisiones > boton "Revisiones") o asignar
-- el lugar correcto antes de reintentar.
SELECT s.codigo, s.proyecto_nombre, s.tipo, s.lugar_resuelto, s.lugar_obs, s.fecha, s.descripcion
FROM staging_revision_obs s
LEFT JOIN project p ON upper(p.project_description) = s.proyecto_nombre
LEFT JOIN ac_revisiones rev ON rev.proyecto_id = p.project_id
  AND rev.tipo = s.tipo
  AND (
    (s.lugar_resuelto IS NOT NULL AND rev.lugar = s.lugar_resuelto)
    OR (
      s.lugar_resuelto IS NULL
      AND (SELECT count(*) FROM ac_revisiones r2 WHERE r2.proyecto_id = p.project_id AND r2.tipo = s.tipo) = 1
    )
  )
WHERE rev.id IS NULL
ORDER BY s.proyecto_nombre, s.tipo;
